import * as React from 'react';
import { Tooltip } from '@patternfly/react-core';
import { NODE_HEIGHT } from './const';
import { getWhenExpressionDiamondState } from './utils';

import './WhenExpressionDecorator.scss';
import { ComputedStatus } from '../../types';

type WhenExpressionDecoratorProps = {
  width: number;
  height: number;
  leftOffset?: number;
  stroke?: string;
  status: ComputedStatus;
  appendLine?: boolean;
  enableTooltip?: boolean;
  isFinallyTask: boolean;
  isPipelineRun: boolean;
};

const WhenExpressionDecorator: React.FC<WhenExpressionDecoratorProps> = ({
  width,
  height,
  enableTooltip,
  appendLine = false,
  status,
  leftOffset = 2,
  isFinallyTask,
  isPipelineRun,
}) => {
  const nodeRef = React.useRef();
  const rotation = 45; // 45deg
  const { tooltipContent, diamondColor } = getWhenExpressionDiamondState(
    status,
    isPipelineRun,
    isFinallyTask,
  );
  const diamondHeight =
    Math.round(width * Math.sin(rotation)) +
    Math.round(height * Math.cos(rotation));
  const diamondNode = (
    <g
      transform={`translate(-${width * leftOffset}, ${
        NODE_HEIGHT / 2 - diamondHeight / 2
      })`}
      ref={nodeRef}
    >
      <rect
        data-test="diamond-decorator"
        className="opp-when-expression-decorator-diamond"
        width={width}
        height={height}
        fill={diamondColor}
        stroke={
          isPipelineRun
            ? diamondColor
            : 'var(--pf-t--global--border--color--100)'
        }
      />
      {appendLine && (
        <line
          x1={diamondHeight / 2}
          y1={diamondHeight / 2}
          x2={width * leftOffset}
          y2={diamondHeight / 2}
          stroke="var(--pf-t--global--border--color--100)"
          data-test="diamond-decorator-line"
        />
      )}
    </g>
  );

  return enableTooltip ? (
    <Tooltip
      triggerRef={nodeRef}
      position="bottom"
      enableFlip={false}
      content={<div data-test="when-expression-tooltip">{tooltipContent}</div>}
    >
      {diamondNode}
    </Tooltip>
  ) : (
    diamondNode
  );
};

export default WhenExpressionDecorator;

